  try {
    // Rate limiting
    await rateLimitService.checkLimit(userId, "createTeam", rateLimits.web.forms);

    // Validation
    await ValidationService.validateOrThrow(createTeamSchema, { userId, name });

    // Metrics start
    const startTime = Date.now();

